# icon_utils.py (utils 패키지) — 앱 아이콘 경로 및 Base64 데이터 제공

import base64
import os
import tempfile

ICON_BASE64 = ""


def get_icon_path():
    """Base64를 디코딩해 임시 폴더에 .ico로 저장한 뒤 절대 경로 반환."""
    if not ICON_BASE64:
        return None
    try:
        temp_dir = tempfile.gettempdir()
        icon_path = os.path.join(temp_dir, "gichan_formant_icon.ico")
        with open(icon_path, "wb") as f:
            f.write(base64.b64decode(ICON_BASE64))
        return icon_path
    except Exception as e:
        print(f"[icon_utils] 아이콘 파일 생성 실패: {e}")
        return None
